console.log(`Inserting ${lessons.length} lessons...`);
let count = 0;
for (const lesson of lessons) {
  await client.query(
    `INSERT INTO lessons (course_id, title, content, "order", duration_minutes, image_url, challenges) VALUES ($1,$2,$3,$4,$5,$6,$7)`,
    [lesson.c, lesson.t, lesson.content, lesson.o, lesson.d, lesson.img, JSON.stringify(lesson.ch)]
  );
  count++;
  if (count % 10 === 0) process.stdout.write(`  ${count}/${lessons.length} inserted...\n`);
}
console.log(`Done! ${count} lessons inserted.`);
await client.end();
